using System;

unsafe {
    // stackalloc with nint
    Span<nint> span = stackalloc nint[4];
    span[0] = 10;
    span[1] = 20;
    span[2] = 30;
    span[3] = 40;

    Console.WriteLine($"nint Span length: {span.Length}");
    for (int i = 0; i < span.Length; i++)
        Console.WriteLine($"  span[{i}] = {span[i]}");
    Console.WriteLine($"sizeof(nint) = {sizeof(nint)} bytes");

    // stackalloc with nuint
    Span<nuint> uspan = stackalloc nuint[2];
    uspan[0] = 100;
    uspan[1] = 200;
    Console.WriteLine($"nuint Span length: {uspan.Length}, values: {uspan[0]}, {uspan[1]}");
}
PROG
# Enable unsafe and set lang version
sed -i 's|</PropertyGroup>|<AllowUnsafeBlocks>true</AllowUnsafeBlocks>\n</PropertyGroup>|' StackAllocTest.csproj
dotnet run 2>&1

